//! Frozen gradient correction tables for the projected c1 filter.
//!
//! Generated by `cargo run -p halcyon-quote --bin gen_gradient_tables`.

/// Number of mean_u sample points for interpolated corrections.
pub const N_MU_SAMPLES: usize = 4;
/// Reference mean_u values (S6 scale) at which corrections are precomputed.
pub const MU_SAMPLES: [i64; N_MU_SAMPLES] = [-2000, 0, 2000, 4000];

#[derive(Debug, Clone, Copy)]
pub struct FrozenRegionTables<const K: usize> {
    pub probability: [[i64; K]; 6],
    pub correction_u: [[i64; K]; 6],
    pub correction_v: [[i64; K]; 6],
    pub correction_u_interp: [[[i64; K]; 6]; N_MU_SAMPLES],
    pub correction_v_interp: [[[i64; K]; 6]; N_MU_SAMPLES],
    pub probability_interp: [[[i64; K]; 6]; N_MU_SAMPLES],
}

#[derive(Debug, Clone, Copy)]
pub struct FrozenMomentTables<const K: usize> {
    pub safe_autocall: FrozenRegionTables<K>,
    pub safe_ki: FrozenRegionTables<K>,
    pub knocked_autocall: FrozenRegionTables<K>,
}

